"""-Builds a dictionary file for the program-This file just lists the quantum numbers for each transition in ascending order by J, and then by tau (Ka-Kc) within each J-This is currently only setup to do delta J=0 or 1, and delta Ka/Kc = 0 or 1 transitions"""import numpy as npMaxJ = 25	#Highest J you want the dictionary to run toOutFile = "Base Catalog Dictionary1.txt"	#Dictionary file nameFileString = ""FileString += "Energy Levels:\n"FileString += "Index\tQN1\tQN2\tQN3\n"J = 0FileString += "%d\t%d\t%d\t%d\n" % (0,0,0,0)	#For simplicity we output J=0 before the loopsCount = 1										#Keep track of how many transitions have been written, and use this as the labelwhile (J < MaxJ+1):	#The +1 is the same as other python scrips, to ensure that MaxJ is the actual max J output	Ka = 0			#Start from tau = -J	Kc = J	while (Ka < J):	#Loop through all the values of Ka (0 through J)		FileString += "%d\t%d\t%d\t%d\n" % (Count,J,Ka,Kc)		print(J,Ka,Kc)		Ka+=1		Count+=1		FileString += "%d\t%d\t%d\t%d\n" % (Count,J,Ka,Kc)		Count+=1		print(J,Ka,Kc)		Kc-=1		if (Ka == J):			FileString += "%d\t%d\t%d\t%d\n" % (Count,J,Ka,Kc)			print(J,Ka,Kc)			Count+=1	J+=1FileHandle = open(OutFile,"w")	FileHandle.write(FileString)FileHandle.close()print ("Wrote %d lines to Base Catalog file: %s" % (Count,OutFile))